--
-- Table structure for table `product_group`
--

DROP TABLE IF EXISTS `product_group`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_group` (
  `product_group_id` int NOT NULL,
  `category_id` int NOT NULL,
  `subcategory_id` int NOT NULL,
  `manufacturer_id` int NOT NULL,
  `group_description` varchar(200) NOT NULL,
  `group_information` varchar(5000) NOT NULL,
  `group_code` varchar(1000) NOT NULL,
  PRIMARY KEY (`product_group_id`),
  KEY `CategoryID` (`category_id`),
  KEY `SubcategoryID` (`subcategory_id`),
  KEY `ManufacturerID` (`manufacturer_id`),
  CONSTRAINT `product_group_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `product_category` (`category_id`),
  CONSTRAINT `product_group_ibfk_2` FOREIGN KEY (`subcategory_id`) REFERENCES `product_subcategory` (`subcategory_id`),
  CONSTRAINT `product_group_ibfk_3` FOREIGN KEY (`manufacturer_id`) REFERENCES `product_manufacturer` (`manufacturer_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

