LOCK TABLES `product_group` WRITE;
/*!40000 ALTER TABLE `product_group` DISABLE KEYS */;
INSERT INTO `product_group` VALUES (1,1,5,4,'Liquitex Professional Spray Paint','This is a very different kind of spray paint. Liquitex Spray Paint is a fine art tool made with highly lightfast* artist-quality pigments. Unlike regular sprays, it uses low-odor professional paint made with water-based technology and low solvents. Perfect for the studio. *Fluorescent and metallic pigments are naturally less lightfast.','liquitex-professional-spray-paint'),(2,1,2,4,'Liquitex Basics Acrylic','Basics is for all - from those new to painting, to experienced artists. Ideal if you’re a beginner. If you’re on a budget. Perfect for underpainting or sketching if you’re a serious artist. And for color scoping and exploration if you’re a creative professional. This medium viscosity paint is made with lightfast, artist-quality pigments in an expanded choice of colors.','liquitex-basics-acrylic'),(3,1,2,4,'Liquitex Basics Acrylic Metallic','Basics is for all - from those new to painting, to experienced artists. Ideal if you’re a beginner. If you’re on a budget. Perfect for underpainting or sketching if you’re a serious artist. And for color scoping and exploration if you’re a creative professional. This medium viscosity paint is made with lightfast, artist-quality pigments in an expanded choice of colors.','liquitex-basics-acrylic-metallic'),(4,1,2,4,'Liquitex Basics Acrylic Metallic Set 6x118ml','Turn up the luster and dive into a world of vibrant metallics. Discover six tubes of highly burnished, opaque acrylic paint, with a medium consistency bursting with metallic mica and artist quality pigments. 6 x 118ml tubes - Metallic Red, Metallic Magenta, Metallic Purple, Metallic Blue, Metallic Aqua Green, Metallic Green','liquitex-basics-acrylic-metallic-set-6x118ml'),(5,1,2,4,'Liquitex Special Release Muted Collection Soft Body Acrylic Set','This is Soft Body Acrylic. This color set gives you endless mixing options, while Transparent Mixing White and Ivory Black can be used on their own, or to shade and tint.','liquitex-soft-body-acrylic-set-6x22ml-mixing'),(6,1,2,4,'Liquitex Heavy Body Acrylic','This is high viscosity, pigment-rich professional acrylic color, ideal for impasto and texture. With a high concentration of lightfast artist-quality pigment and a satin finish, Heavy Body Acrylic gives you rich, permanent color, with crisp brush strokes and knife marks.','liquitex-heavy-body-acrylic'),(7,2,7,13,'Winsor & Newton Canvas Professional Cotton Deep Edge','Traditional Canvas with medium texture, ideal for use with oil and acrylic paints.','winsor-newton-canvas-professional-cotton-deep-edge'),(8,2,7,13,'Winsor & Newton Canvas Professional Linen Traditional','Our canvases are made to perform. Choose from a range of sizes and quality materials within both our Classic and Professional collections.','winsor-newton-canvas-professional-linen-traditional'),(9,2,7,13,'Winsor & Newton Canvas Professional Cotton Traditional','Traditional Canvas with medium texture, ideal for use with oil and acrylic paints.','winsor-newton-canvas-professional-cotton-traditional'),(10,1,2,4,'Liquitex Basics Acrylic Metallic Set 6x22ml','Turn up the luster and dive into a world of vibrant metallics. Discover six tubes of highly burnished, opaque acrylic paint, with a medium consistency bursting with metallic mica and artist quality pigments. 6 x 118ml tubes - Metallic Red, Metallic Magenta, Metallic Purple, Metallic Blue, Metallic Aqua Green, Metallic Green','liquitex-basics-acrylic-metallic-set-6x22ml'),(11,1,1,13,'Winsor & Newton Artists’ Oil','Our Artist\'s Oil Colours, made from only the finest pigments. We carefully formulate each tone for stability, tinting strength and coverage. Use them thickly with palette knives or brushes, or thin them to a very fine glaze.','winsor-newton-artists-oil'),(12,2,7,13,'Winsor & Newton Canvas Classic Cotton Deep Edge','Our canvases are made to perform. Choose from a range of sizes and quality materials within both our Classic and Professional collections.','winsor-newton-canvas-classic-cotton-deep-edge'),(13,2,7,13,'Winsor & Newton Canvas Classic Cotton Traditional','Our canvases are made to perform. Choose from a range of sizes and quality materials within both our Classic and Professional collections.','winsor-newton-canvas-classic-cotton-traditional'),(14,2,6,4,'Liquitex Professional Recycled Canvas Unprimed Roll','This canvas cloth is made with 100% recycled plastic bottles fastened to FSC certified wood. Suitable for both acrylic and oil paints, this high-quality surface has been tested by professional artists and within our lab so you can create with confidence while reducing your impact on the environment.','liquitex-professional-recycled-canvas-unprimed-roll'),(15,1,1,13,'Winsor & Newton Artists’ Oil Set 10 x 21 ml','This introductory set contains a larger selection of 10 x 21ml tubes of Artists\' Oil Colour. Includes, Winsor Yellow, Crimson Alizarine, Green Ultramarine Hue, Winsor Blue (Red Hue), Winsor Green, Yellow Ochre, Indian Red, Burnt Umber, Ivory Black, Titanium White. Actual contents may vary.','winsor-newton-artists-oil-set-10x21ml'),(16,1,1,13,'Winsor & Newton Artists’ Oil Primary Colour Set','Mix, experiment, and create with our expertly formulated Primary Colours Set to inspire a palette of endless possibilities. 5x37ml Tubes: Winsor Lemon, Winsor Blue (Red Shade), Permanent Rose, Titanium White, Lamp Black','winsor-newton-artists-oil-set-primary-colour'),(17,1,1,13,'Winsor & Newton Artists’ Oil Winsor Colour Set','Explore our carefully curated selection of Winsor Colours, offering a perfectly formulated palette showcasing our heritage and expertise. 5x37ml Tubes: Winsor Yellow, Winsor Orange, Winsor Red, Winsor Violet (Dioxazine), Winsor Blue (Green Shade)','winsor-newton-artists-oil-set-winsor-colour'),(18,1,1,13,'Winsor & Newton Artists’ Oil Set 6 x 21 ml','A small tube set containing 6 x 21ml tubes of Winton Oil Colour. Includes: Cadmium Yellow Pale Hue, Cadmium Red Deep Hue, French Ultramarine, Viridian Hue, Yellow Ochre, Burnt Umber. Actual contents may vary.','winsor-newton-artists-oil-set-6x21ml'),(19,1,3,13,'Winsor & Newton Professional Watercolour','Our Professional Watercolour range offers bright, vibrant colours and unrivalled performance. Watercolour, more than any other medium, reflects the unique characteristics of the pigments used and our Professional Watercolours use only the finest pigments, and are known for their brilliance, permanence and strength of colour. The transparency of our Professional Watercolour is achieved by our unique process of pigment dispersion during manufacture. The natural characteristics of each pigment highlights the paint’s transparency level.','winsor-newton-professional-watercolour'),(20,1,3,13,'Winsor & Newton Cotman Watercolour','Fine Art Pigments Cotman Watercolours uses fine art pigments with reduced pigment load than the Professional Watercolour range, making them an accessible choice while still uncompromising on quality.','winsor-newton-cotman-watercolour'),(21,1,1,13,'Winsor & Newton Griffin Alkyd Fast Drying Oil','Traditional oils, wonderful as they are, take a very long time to dry. That\'s why we created our Griffin Alkyds - they dry much more quickly and this means impasto and glazing techniques can be done in a single session.These oil tones have a slightly greater level of transparency for increased depth and clarity when glazing. Our Griffins are a bit more fluid in consistency than traditional oils and they dry with a somewhat more reflective surface, too.','winsor-newton-griffin-alkyd-fast-drying-oil'),(22,1,3,13,'Winsor & Newton Cotman Watercolor Set - Compact Set','Discover 14 Cotman Watercolours made with quality, fine art pigments. This set is ideal for outdoor use as it includes a brush and palettes with multiple mixing areas. Field Set was previously named The Compact Set.','winsor-newton-cotman-watercolor-compact-set'),(23,1,3,13,'Winsor & Newton Cotman Watercolor Set - Field Travel Set','Discover 12 Cotman Watercolours made with quality, fine art pigments in a travel set. This set is ideal for outdoor watercolour painting, especially for extensive colour mixing. The Field Travel Set opens up to reveal a travel brush, 60mL water bottle, 2 clip-on water pots, and 3 palettes with mutliple mixing areas. Field Travel Set previously named Field Plus.','winsor-newton-cotman-watercolor-set-field-box'),(24,3,11,13,'Winsor & Newton Oil Brushes Artists Hog Brushes Bright','A short flat head. Creates sharp edges with control.Manufactured with a shorter bristle length, these brushes offer greater control to the artist.','winsor-newton-oil-brushes-artists-hog-brushes-bright'),(25,3,11,13,'Winsor & Newton Oil Brushes Artists Hog Brushes Flat','A long flat head. For blending, glazing or covering large areas.This range of brushes features a longer bristle length for greater colour carrying capacity','winsor-newton-oil-brushes-artists-hog-brushes-flat'),(26,3,11,13,'Winsor & Newton Oil Brushes Artists Hog Brushes Round','For fine detail, lines glazes.A traditional round shape head which is ideal for use when accuracy and detail is required.','winsor-newton-oil-brushes-artists-hog-brushes-round'),(27,3,11,13,'Winsor & Newton Oil Brushes Artists Hog Brushes Filbert','Flat head with oval tip. Creates a broad mark with a soft edge.Similar to the Extra Long Filbert, these brushes have a shorter, thick shape for extra control.','winsor-newton-oil-brushes-artists-hog-brushes-filbert'),(28,3,11,13,'Winsor & Newton Oil Brushes Artists\' Synthetic Hog Brushes 4 Pack','This set comes with 4 Artists\' Oil Synthetic Hog Brushes in a handy canvas wallet for storing and carrying, all designed to accompany the artist on their creative journey. The wallet has a Velcro closure and 7 inner pockets. 6 pockets are ideal for long handle brushes (max. 330 mm length) and 1 wider pocket can carry additional painting utensils.','winsor-newton-oil-brushes-artists-synthetic-hog-brushes-set'),(29,3,11,13,'Winsor & Newton Oil Brushes Hog Brush Long Handle 5 Pack','A natural bristle brush developed for use with Winton Oil Colour.Made from good quality Chinese hog bristles, Winton Hog brushes are interlock constructed and hand-set into seamless corrosion-resistant ferrules. The bristles’ natural curve is retained even after heavy use, allowing more control and accuracy, whether painting with oils or acrylics.','winsor-newton-oil-brushes-hog-brush-long-handle-set'),(30,3,12,13,'Winsor & Newton Acrylic Brushes Galeria Short Handle Round','Specifically designed for use with acrylic colour. The versatility of acrylic colour can place heavy demands on brushes so this range has been created to be strong, resilient and flexible.The mix of synthetic filaments provide responsiveness and control for thicker application of colour, whilst maintaining shape retention, regardless of how much water you use.','winsor-newton-acrylic-brushes-galeria-short-handle-round'),(31,3,12,13,'Winsor & Newton Acrylic Brushes Galeria Long Handle Round','Specifically designed for use with acrylic colour. The versatility of acrylic colour can place heavy demands on brushes so this range has been created to be strong, resilient and flexible.The mix of synthetic filaments provide responsiveness and control for thicker application of colour, whilst maintaining shape retention, regardless of how much water you use.','winsor-newton-acrylic-brushes-galeria-long-handle-round'),(32,3,12,13,'Winsor & Newton Acrylic Brushes Galeria Long Handle Bright','Specifically designed for use with acrylic colour. The versatility of acrylic colour can place heavy demands on brushes so this range has been created to be strong, resilient and flexible.The mix of synthetic filaments provide responsiveness and control for thicker application of colour, whilst maintaining shape retention, regardless of how much water you use.','winsor-newton-acrylic-brushes-galeria-long-handle-bright'),(33,4,15,18,'Stillman & Birn Delta Series Wirebound Premium Sketchbook, 7\" x 10\"','The Delta Series Sketchbook from Stillman & Birn features extra heavyweight, 270 gsm white paper wirebound with a high-density board, resistant to warping. The white, mixed media cold press paper has a substantial tooth and works well with all dry media, wet media, light washes, and inks. Portrait, 7\" x 10\".  25 sheets, 52 pages.','stillman-&-birn-delta-series-wirebound-premium-sketchbook'),(34,4,15,18,'Stillman & Birn Beta Series Hardbound Premium Sketchbook, 5.5\" x 8.5\"','The Beta Series Sketchbook from Stillman & Birn features extra heavyweight, 270 gsm white paper hardbound with a high-density board, resistant to warping. The white, mixed media cold press paper has a substantial tooth and works well with all wet media, dry media, light washes, and inks. Portrait, 5.5\" x 8.5\".  26 sheets, 52 pages.','stillman-&-birn-beta-series-hardbound-premium-sketchbook'),(35,4,15,18,'Stillman & Birn Nova Series Wirebound Premium Sketchbook','The Nova Series Sketchbook from Stillman & Birn features heavyweight, 150 gsm white paper wirebound with high density board, resistant to warping. The white, mixed media paper has a medium grain surface and works well with all dry media, light washes, and inks. This portrait sketchbook comes in a few different sizes and colors, select from the dropdown below. Portrait, 6\" x 8\" 50 sheets, 100 pages.','stillman-&-birn-nova-series-wirebound-premium-sketchbook'),(36,3,12,13,'Winsor & Newton Acrylic Brushes Galeria Long Handle Filbert','Specifically designed for use with acrylic colour. The versatility of acrylic colour can place heavy demands on brushes so this range has been created to be strong, resilient and flexible.The mix of synthetic filaments provide responsiveness and control for thicker application of colour, whilst maintaining shape retention, regardless of how much water you use. Filbert has a flat head with an oval tip for creating a broad mark with a soft edge.','winsor-newton-acrylic-brushes-galeria-long-handle-filbert'),(37,3,12,13,'Winsor & Newton Acrylic Brushes Galeria Long Handle Flat','Specifically designed for use with acrylic colour. The versatility of acrylic colour can place heavy demands on brushes so this range has been created to be strong, resilient and flexible.The mix of synthetic filaments provide responsiveness and control for thicker application of colour, whilst maintaining shape retention, regardless of how much water you use.','winsor-newton-acrylic-brushes-galeria-long-handle-flat'),(38,3,12,13,'Winsor & Newton Acrylic Brushes University Series 233 Round','University is a range of white synthetic general-purpose brushes. Featuring distinctive red handles with white tips, University Brushes are stiff enough to use with more fluid oils yet soft enough to use with watercolours. Additionally, when used with oils and acrylics, brush marks are not as visible. University brushes offer excellent spring controllability and will last a considerable length of time if properly cared for. They offer an affordable option for students or those looking for a multi-purpose brush.','winsor-newton-acrylic-brushes-university-short-handle-round'),(39,3,12,13,'Winsor & Newton Acrylic Brushes University Series 235 Flat','A short flat head. Creates sharp edges with controlThe brush head is the same as series 234, the longer handle is generally more suitable for oil and acrylic painters.','winsor-newton-acrylic-brushes-university-short-handle-flat'),(40,3,12,13,'Winsor & Newton Acrylic Brushes University Series 238 Fan','University is a range of white synthetic general-purpose brushes. Featuring distinctive red handles with white tips, University Brushes are stiff enough to use with more fluid oils yet soft enough to use with watercolours. Additionally, when used with oils and acrylics, brush marks are not as visible. University brushes offer excellent spring controllability and will last a considerable length of time if properly cared for. They offer an affordable option for students or those looking for a multi-purpose brush. Fan is for blending, softening edges and creating textures.','winsor-newton-acrylic-brushes-university-long-handle-fan'),(41,3,12,13,'Winsor & Newton Acrylic Brushes Foundation Brush Set','White synthetic brushes primarily for use with acrylic colour; also suitable for oil colour. Available in short and long handle packs.Contains Round 1, 3 & 5.','winsor-newton-acrylic-brushes-foundation-brush-set'),(42,3,13,13,'Winsor & Newton Watercolor Brushes Sceptre Gold ll Brush','Sceptre Gold II is a range of high quality brushes made from a mix of sable and synthetic fibres. Ideal for working with watercolour and fluid oil colour, they are also suitable for use with acrylic, water mixable oil and alkyd fast drying oil colour.Sceptre Gold II is a perfect combination, giving a performance close to sable at a price close to synthetic.','winsor-newton-watercolor-brushes-sceptre-gold-ll-brush'),(43,3,13,13,'Winsor & Newton Watercolor Brushes Cotman Series 111 Round','For fine detail, lines and washes. A traditional and popular head shape for all-purpose watercolour work. Can be used for broad strokes yet it will also form a sharp point.','winsor-newton-watercolor-brushes-cotman-series-111-round'),(44,3,13,13,'Winsor & Newton Watercolor Brushes Cotman Series 333 Rigger','An extra fine point for painting lines, long scroll work and detail.','winsor-newton-watercolor-brushes-cotman-series-333-rigger'),(45,1,4,13,'Winsor & Newton Designers Gouache','Winsor & Newton Designers Gouache offers a smooth, opaque professional gouache with high levels of pigmentation. All Winsor Newton Designer Gouache colors are fully intermixable and dry to a matte finish.  Available in 14 and 37 ml.','winsor-newton-designers-gouache'),(46,3,13,13,'Winsor & Newton Watercolor Brushes Cotman Series 668 Filbert','An extra fine point for painting lines, long scroll work and detail.','winsor-newton-watercolor-brushes-cotman-series-668-filbert'),(47,3,13,13,'Winsor & Newton Watercolor Brushes Cotman Series 667 Angled','The point can be used for detailed work, or it can be pressed to create a curved or straight wedge.','winsor-newton-watercolor-brushes-cotman-series-667-angled'),(48,3,13,13,'Winsor & Newton Watercolor Brushes Professional Synthetic Sable Brush Set','This set comes with 4 Professional Watercolour Synthetic Sable Brushes in a handy canvas wallet for storing and carrying, all designed to accompany the artist on their creative journey. The wallet has a Velcro closure and 7 inner pockets. 6 pockets are ideal for short handle brushes (max. 240 mm length) and 1 wider pocket can carry additional painting utensils.','winsor-newton-watercolor-brushes-professionals-synthetic-sable-brush-set'),(49,3,14,13,'Winsor & Newton Watercolor Brushes Professional Synthetic Sable Brush Set','This set comes with 4 Professional Watercolour Synthetic Sable Brushes in a handy canvas wallet for storing and carrying, all designed to accompany the artist on their creative journey. The wallet has a Velcro closure and 7 inner pockets. 6 pockets are ideal for short handle brushes (max. 240 mm length) and 1 wider pocket can carry additional painting utensils.','winsor-newton-watercolor-brushes-professionals-synthetic-sable-brush-set'),(50,3,14,13,'Winsor & Newton Oil Brushes Artists\' Synthetic Hog Brushes 4 Pack','This set comes with 4 Artists\' Oil Synthetic Hog Brushes in a handy canvas wallet for storing and carrying, all designed to accompany the artist on their creative journey. The wallet has a Velcro closure and 7 inner pockets. 6 pockets are ideal for long handle brushes (max. 330 mm length) and 1 wider pocket can carry additional painting utensils.','winsor-newton-oil-brushes-artists-synthetic-hog-brushes-set'),(51,3,14,13,'Winsor & Newton Oil Brushes Hog Brush Long Handle 5 Pack','A natural bristle brush developed for use with Winton Oil Colour.Made from good quality Chinese hog bristles, Winton Hog brushes are interlock constructed and hand-set into seamless corrosion-resistant ferrules. The bristles’ natural curve is retained even after heavy use, allowing more control and accuracy, whether painting with oils or acrylics.','winsor-newton-oil-brushes-hog-brush-long-handle-set'),(52,3,14,13,'Winsor & Newton Acrylic Brushes Foundation Brush Set','White synthetic brushes primarily for use with acrylic colour; also suitable for oil colour. Available in short and long handle packs.Contains Round 1, 3 & 5.','winsor-newton-acrylic-brushes-foundation-brush-set'),(53,2,7,4,'Liquitex Professional Recycled Canvas Plastic Traditional','This canvas cloth is made with 100% recycled plastic bottles fastened to FSC certified wood. Suitable for both acrylic and oil paints, this high-quality surface has been tested by professional artists and within our lab so you can create with confidence while reducing your impact on the environment.','liquitex-professional-recycled-canvas-plastic-traditional'),(54,2,7,4,'Liquitex Professional Recycled Canvas Plastic Deep Edge','This canvas cloth is made with 100% recycled plastic bottles fastened to FSC certified wood. Suitable for both acrylic and oil paints, this high-quality surface has been tested by professional artists and within our lab so you can create with confidence while reducing your impact on the environment.','liquitex-professional-recycled-canvas-plastic-deep-edge'),(55,2,7,4,'Liquitex Basics Cotton Canvas (3pack) ','The trio pack. Put color to surface with three ready-to-go painting canvases. Archival. Acid-free. Non-toxic. No need to wait. The medium texture cotton canvas is pre-primed with a triple layer of acrylic gesso all set to receive acrylic color. Stapled at the rear, stretched on a FSC MIX wood frame.','liquitex-basics-cotton-canvas'),(56,2,8,4,'Liquitex Basics Acrylic Pad','Put color to paper with these ultra-useful canvas paper pads. When you don’t want to go with a canvas, but need something reliable, this is your go-to. 12 white, acid-free paper sheets with the subtle texture of canvas texture, bound together and easy to store. Perfect surface for acrylics in a choice of three sizes.','liquitex-basics-acrylic-pad'),(57,2,9,13,'Winsor & Newton Artists Canvas Board','For general use with oil (including water mixable), acrylic and alkyd color.','winsor-newton-artists-canvas-board'),(58,2,9,13,'Winsor & Newton Artists Canvas Board (3 pack)','For general use with oil (including water mixable), acrylic and alkyd color.','winsor-newton-artists-canvas-board-multi'),(59,5,22,13,'Winsor & Newton Medium Kneaded Rubber','A medium size ‘plastic’ or ‘putty’ rubber which may be moulded to a fine point for minute erasures. Useful for picking out highlights and erasing pencil, chalk or charcoal without smearing. ','winsor-newton-medium-kneaded-rubber'),(60,5,20,13,'Winsor & Newton Promarker','Twin-tipped, for greater flexibility Winsor & Newton Promarker comes with a high-quality broad chisel nib for broad strokes to shade larger areas, and a fine bullet tip for precision.','winsor-newton-promarker'),(61,5,20,13,'Winsor & Newton Promarker Brush','The Winsor & Newton Promarker Brush provides the ultimate in precise and flexible line control, adding versatility to your drawing and illustration practice. The colour rich range is highly blendable and offers print quality, streak-free coverage. Colour ranging from subtle pastels to bold, vibrant hues.Blend-friendly,with malleable, alcohol-based, translucent ink.Twin-tipped, with a broad chisel nib and brush nib.High quality nibs for print-quality, streak-free coverage.','winsor-newton-promarker-brush'),(62,5,20,13,'Winsor & Newton Promarker Watercolour','You won\'t find another marker quite like these ones - we decided to get creative and make watercolour in pen form. Blending varies depending on the paper you use, but they\'re designed to make gorgeous washes when combined with water. Because they have dual nibs, you can also use them for fine detail and sweeping line thicknesses. To see them at their best, always use them with our Winsor & Newton watercolour paper.','winsor-newton-promarker-watercolour'),(63,5,20,13,'Winsor & Newton Promarker Neon','Promarker Neon offers brilliant, fluorescent colours in high quality water-based ink. Pigmented and lightfast, it is perfect for adding vibrant highlights, definition and texture to your designs. It also glows under UV light. Each pen is twin-tipped, with a broader bullet nib suitable for filling in large areas, and a smaller one for detailed work.','winsor-newton-promarker-neon'),(64,5,20,13,'Winsor & Newton Promarker Metallic','Promarker Metallic offers intense, shimmery colours, perfect for adding highlights and texture to your designs. The pigment-based ink used is lightfast enough to provide long-lasting results. Each pen is twin-tipped, with a broader bullet nib suitable for filling in large areas, and a smaller one for detailed work.','winsor-newton-promarker-metallic'),(65,5,20,13,'Winsor & Newton Promarker Watercolour Collection','Promarker Watercolour offers all the attributes of watercolour paint, but in a twin-tipped marker with a flexible brush-tip and a fine point. The water based pigmented ink in these markers allow you to create beautiful painterly effects when mixed with water. And thanks to the high quality pigments, your work will not fade. Perfect and convenient for creating gorgeous, expressive artworks on the go. For best results, use them on Winsor & Newton watercolour paper. Store horizontally.','winsor-newton-promarker-watercolour-collection'),(66,5,20,13,'Winsor & Newton Promarker Collection','Explore the extensive Promarker colour spectrum with this 24-strong colour kit. As with all Promarker sets, it has been specifically curated to provide illustrators and artists with beautiful colours, every day. Please Note: Both sets pictured here contain the same colours. The markers in each set contain the same alcohol based dye ink.','winsor-newton-promarker-collection'),(67,5,20,13,'Winsor & Newton Promarker Brush Collection','Embrace the most vibrant Promarker Brush palette possible with Yellow, Pumpkin, Red, Rouge, Magenta, Purple, Cyan, Royal Blue, Bright Green, Lush Green, Cocoa, Warm Grey 5 and Black. Like all Promarker Brushs, the 12 shades can be used with the free colourless Blender to explore graduated tones or more muted shades. These 12 vibrant colours were specifically curated to complement each other and broaden your colour collection.','winsor-newton-promarker-brush-collection'),(68,5,19,13,'Winsor & Newton Sketching Pencil Set 10 Pieces','Discover the pleasure of traditional drawing and sketching with these carefully selected sets of essential pencils and tools. The classic charcoal and graphite pencils included blend easily to create evocative shading, making them ideal for striking life drawings and still life pieces. Brilliantly versatile and responsive, these high-quality pencils are also perfect for spontaneous sketching, allowing you to quickly capture movement and try out new ideas.','winsor-newton-sketching-pencil-set'),(69,5,19,13,'Winsor & Newton Sketching Pencil Set with Eraser 5 Pieces','The classic charcoal pencils included blend easily, making them ideal for striking life drawings and still life pieces. Brilliantly versatile and responsive, these high-quality pencils are also perfect for spontaneous sketching, allowing you to quickly capture movement and try out new ideas. Available in a blister, perfect for students and beginners.','winsor-newton-sketching-pencil-set-x5-with-eraser-set'),(70,5,19,13,'Winsor & Newton Graphite Pencil Set Soft 5 Pieces','Ideal for capturing movement or inspiration on the go, the pencils come in a range of hardness levels for different tasks and tones. H grades are best suited to delicate, intricate drawing, and the softer, darker B grades are best for shading and smooth coverage of large areas. Available in a blister, perfect for students and beginners.','winsor-newton-graphite-pencil-soft'),(71,5,19,13,'Winsor & Newton Graphite Pencil Soft x12 Tin Set','Create everything from beautifully fine-detailed drawings to spontaneous, expressive sketches with these versatile, soft high-quality graphite pencils. Ideal for capturing movement or inspiration on the go, the pencils come in a range of hardness levels for different tasks and tones. H grades, being the hardest, are best suited to delicate, intricate drawing. The softer, darker B grades are best for shading and smooth coverage of large areas. Presented in a sleek, embossed metal travel tin with the iconic Winsor & Newton logo.','winsor-newton-graphite-pencil-soft-x12-tin-set'),(72,5,19,13,'Winsor & Newton Medium Graphite Pencil x12','A range of graphite pencils for sketching and drawing, suitable for blending, smooth-shading and fine detail. Ideal for capturing movement or inspiration on the go, they come in a range of levels of hardness, with H grades best suited to delicate, intricate drawing, and the softer, darker B grades best for shading and smooth coverage of large areas. For the perfect finishing touch, they\'re presented in stylish plain metal tins, embossed with the iconic Winsor & Newton logo.','winsor-newton-medium-graphite-pencil-x12'),(73,5,19,13,'Winsor & Newton Colour Pencil Studio Set Mixed 45 Pieces','Discover a range of 24 rich watercolour pencils, 12 vibrant colour pencils, and 6 graphite pencils all in one beautifully designed box. Includes a watercolour brush, a sharpener, and a paper pad','winsor-newton-colour-pencil-studio-set-mixed'),(74,5,19,13,'Winsor & Newton Colour Pencil Studio Set Mixed 50 Pieces','Explore a range of 50 vibrant colour pencils all in one beautifully designed box. Their soft texture makes blending easy and the high-quality leads mean they\'re beautifully smooth and responsive to use, whether you\'re building up intense colour or working on delicate shading. Set includes a sharpener, and a paper pad.','winsor-newton-colour-pencil-studio-set-mixed-50x'),(75,5,19,13,'Winsor & Newton Colour Pencil Set 12 Pieces','Create artworks that sing with wonderfully rich, vibrant colour with these thick-core pencils. Their soft texture makes blending easy and the high-quality leads mean they\'re beautifully smooth and responsive to use, whether you\'re building up intense colour or working on delicate shading. For the perfect finishing touch, they\'re presented in stylish plain metal tins, embossed with the iconic Winsor & Newton logo.','winsor-newton-colour-pencil-set'),(76,5,19,13,'Winsor & Newton Colour Pencil Studio Set 72 Pieces','Colour Pencils in Metal Tin Highly pigmented wax-based pencils, that are ideal for building up intense colour or adding light shading. Bold and bright colours with break-resistant leads and points.','winsor-newton-colour-pencil-studio-set'),(77,5,19,13,'Winsor & Newton Colour Pencil Wallet Set 27 Pieces','Discover a range of 24 smooth and vibrant pencils in a wallet, their soft texture makes blending easy and the high-quality core mean they\'re responsive to use, whether you\'re building up colour or working on delicate shading. Each pencil sharpens cleanly to a neat, precise point which won\'t break, even under pressure. Set includes two graphite pencils, and a white vinyl eraser.','winsor-newton-colour-pencil-wallet-set'),(78,5,19,13,'Winsor & Newton Watercolour Pencil Set 24 Pieces','Explore stunning watercolour effects and rich, vibrant hues with these versatile thick-core pencils. Use them dry like regular pencils for smooth, vibrant shading and blending, or experiment with a wet brush to transform the pencil colour into paint – perfect for creating gorgeous, expressive artworks on the go. For the perfect finishing touch, they\'re presented in stylish plain metal tins, embossed with the iconic Winsor & Newton logo.','winsor-newton-watercolour-pencil-set'),(79,5,19,13,'Winsor & Newton Studio Collection 72pc Watercolour Pencil Collection','Watercolour Pencils in Metal Tin Highly pigmented wax-based pencils that can be used dry or wet, by adding water with a brush to create beautiful painterly effects. Vibrant colours with break-resistant leads and points.','winsor-newton-studio-collection-72pc-watercolour-pencil-collection'),(80,5,19,13,'Winsor & Newton Studio Collection 50pc Watercolour Pencil Collection','Watercolour pencil collection 50pc Explore the collection of colours from floral, skyscape to skin tones. These highly pigmented wax-based pencils can be used dry as regular colour pencils, or experiment by adding water to your work to create beautiful painterly effects.','winsor-newton-studio-collection-50pc-watercolour-pencil-collection'),(81,5,19,13,'Winsor & Newton Watercolour Pencil Set 12 Pieces','Explore stunning watercolour effects and rich, vibrant hues with these versatile thick-core pencils. Use them dry like regular pencils for smooth, vibrant shading and blending, or experiment with a wet brush to transform the pencil colour into paint – perfect for creating gorgeous, expressive artworks on the go. For the perfect finishing touch, they\'re presented in stylish plain metal tins, embossed with the iconic Winsor & Newton logo.','winsor-newton-watercolour-pencil-set-x12'),(82,5,21,4,'Liquitex Professional Acrylic Ink','Ultra-fluid acrylic with lightfast*, artist-quality pigments. No dyes. No fade. Just pure, permanent color. And like all acrylics, it dries quickly and permanently, with no smudging or bleeding when rewetted or layered. You get pure liquid color in a range of opacities. * Metallic and fluorescent pigments are naturally less lightfast.','liquitex-professional-acrylic-ink'),(83,5,21,13,'Winsor & Newton Fineliner Pens','A fineliner that fits every style of sketching, featuring a smoothly tapered nib and a longer barrel to sit comfortably in the hand and allow for flexible grip adjustments. Optimised for sketching and drawing: water resistant, non-fading pigment ink, consistent and reliable ink flow. Available in black in six sizes 0.05, 0.1, 0.3, 0.5, 0.8 and 1.0 mm Available in Cool Grey and Sepia in 0.1, 0.3 and 0.5 mm.','winsor-newton-fineliner'),(84,5,21,13,'Winsor & Newton Fineliner Black Pen Set 3x','The Black Fineliner Pen fits every style of sketching, featuring a smoothly tapered nib and a longer barrel to sit comfortably in the hand and allow for flexible grip adjustments. A pen that helps you capture your ideas more fluidly. Optimised for sketching and drawing: water resistant, non-fading pigment ink, consistent and reliable ink flow.','winsor-newton-fineliner-set-black-set'),(85,5,21,13,'Winsor & Newton Fineliner Cool Gray Pen Set 3x','The Cool Grey Fineliner Pen is perfect for traditional sketching, featuring a smoothly tapered nib and a longer barrel to sit comfortably in the hand and allow for flexible grip adjustments. Water resistant, non-fading pigment ink, consistent and reliable ink flow. This set includes 3 Cool Grey Fineliners: 0.1, 0.3 and 0.5 mm nibs.','winsor-newton-fineliner-set-cool-gray-set'),(86,5,21,13,'Winsor & Newton Fineliner Sepia Pen Set 3x','The Sepia Fineliner Pen is perfect for traditional sketching, featuring a smoothly tapered nib and a longer barrel to sit comfortably in the hand and allow for flexible grip adjustments. Water resistant, non-fading pigment ink, consistent and reliable ink flow. This set includes 3 Sepia Fineliners: 0.1, 0.3 and 0.5 mm nibs.','winsor-newton-fineliner-set-sepia-set'),(87,5,21,13,'Winsor & Newton Fineliner Black Pen Set 5x','The Black Fineliner Pen fits every style of sketching, featuring a smoothly tapered nib and a longer barrel to sit comfortably in the hand and allow for flexible grip adjustments. A pen that helps you capture your ideas more fluidly. Optimised for sketching and drawing: water resistant, non-fading pigment ink, consistent and reliable ink flow. Included in this set: fineliners in 5 nib sizes 0.1, 0.3, 0.5, 0.8 and 1.0mm.','winsor-newton-fineliner-set-black-assorted-set-5x'),(88,4,16,13,'Winsor & Newton Professional Watercolour Paper Cold Press 300gsm','Rough paper has a pronounced tooth for achieving watercolours paintings with the most texture and granulation effects. Formed in a traditional cylinder mould our watercolour paper gives the appearance of being handmade. All of our watercolour papers are designed to withstand saturation, and this gummed block keeps the paper stretched as it dries. The finished piece is then removed free from any buckling. Each block contains 20 sheets of 300gsm paper.','winsor-newton-professional-watercolour-paper-cold-press'),(89,4,16,13,'Winsor & Newton Professional Watercolour Paper Hot Press 300gsm','Rough paper has a pronounced tooth for achieving watercolours paintings with the most texture and granulation effects. Formed in a traditional cylinder mould our watercolour paper gives the appearance of being handmade. All of our watercolour papers are designed to withstand saturation, and this gummed block keeps the paper stretched as it dries. The finished piece is then removed free from any buckling. Each block contains 20 sheets of 300gsm paper.','winsor-newton-professional-watercolour-paper-hot-press'),(90,4,16,13,'Winsor & Newton Professional Watercolour Paper Rough 300gsm','Rough paper has a pronounced tooth for achieving watercolours paintings with the most texture and granulation effects. Formed in a traditional cylinder mould our watercolour paper gives the appearance of being handmade. All of our watercolour papers are designed to withstand saturation, and this gummed block keeps the paper stretched as it dries. The finished piece is then removed free from any buckling. Each block contains 20 sheets of 300gsm paper.','winsor-newton-professional-watercolour-paper-rough'),(91,4,16,13,'Winsor & Newton Professional Watercolour Paper Sheet Cold Press 300gsm','Hot-pressed paper is the smoothest watercolour paper with almost no tooth. With its even surface it is often used for consistent washes and fine detail. Formed in a traditional cylinder mould our watercolour paper gives the appearance of being handmade. All of our watercolour papers are designed to withstand saturation, and this paper sheet has 4 sides with soft torn deckle edges and a watermark as a symbol of authenticity and distinction. Each bag contains 10 sheets of 300gsm paper.','winsor-newton-professional-watercolour-paper-sheet-cold-press'),(92,4,16,13,'Winsor & Newton Professional Watercolour Paper Sheet Hot Press 300gsm','Hot-pressed paper is the smoothest watercolour paper with almost no tooth. With its even surface it is often used for consistent washes and fine detail. Formed in a traditional cylinder mould our watercolour paper gives the appearance of being handmade. All of our watercolour papers are designed to withstand saturation, and this paper sheet has 4 sides with soft torn deckle edges and a watermark as a symbol of authenticity and distinction. Each bag contains 10 sheets of 300gsm paper.','winsor-newton-professional-watercolour-paper-sheet-hot-press'),(93,4,16,13,'Winsor & Newton Professional Watercolour Paper Sheet Rough 300gsm','Hot-pressed paper is the smoothest watercolour paper with almost no tooth. With its even surface it is often used for consistent washes and fine detail. Formed in a traditional cylinder mould our watercolour paper gives the appearance of being handmade. All of our watercolour papers are designed to withstand saturation, and this paper sheet has 4 sides with soft torn deckle edges and a watermark as a symbol of authenticity and distinction. Each bag contains 10 sheets of 300gsm paper.','winsor-newton-professional-watercolour-paper-sheet-rough'),(94,4,16,13,'Winsor & Newton Professional Watercolour Journal Spiral Bound Cold Press 300gsm 5” x 7”','Cold-pressed paper has a medium grain with a less pronounced tooth than rough paper, and is an all-round paper for both detail and textured effects. Formed in a traditional cylinder mould our watercolour paper gives the appearance of being handmade. All of our watercolour papers are designed to withstand saturation, and this spiral journal is an ideal size and format for painting on the go. Each pad contains 15 sheets of 300gsm paper.','winsor-newton-professional-watercolour-journal-sprial-bound-cold-press'),(95,4,16,13,'Winsor & Newton Watercolour Journal Spiral Bound Cold Press 300gsm','This cold-pressed paper has a medium grain and is thought to produce the brightest watercolour paintings. This is because the increased surface area reflects more light. All of our watercolour papers are designed to withstand saturation, so you can be confident the paper won’t cockle.','winsor-newton-watercolour-journal-sprial-bound-cold-press'),(96,4,16,13,'Winsor & Newton Watercolour Pad Cold Press 300gsm','This cold-pressed paper has a medium grain and is thought to produce the brightest watercolour paintings. This is because the increased surface area reflects more light. All of our watercolour papers are designed to withstand saturation, so you can be confident the paper won’t cockle.','winsor-newton-watercolour-pad'),(97,4,17,13,'Winsor & Newton Drawing Paper Spiral Pad Medium 150gsm','Medium Surface Drawing Paper is suitable for a variety of drawing and sketching applications and media including pencil, coloured pencil, pastel, oil pastel and charcoal. The paper weights range from 150-220gsm and are available in gummed and spiral pads, sheets and roll.','winsor-newton-drawing-paper-spiral-pad-medium'),(98,4,17,13,'Winsor & Newton Drawing Paper Spiral Pad Smooth 150gsm','Smooth Surface Drawing Paper is suitable for a variety of drawing and sketching techniques such as calligraphy, technical pen and coloured pencil techniques. The paper weights range from 150-220gsm and are available in gummed and spiral pads, sheets and roll.','winsor-newton-drawing-paper-spiral-pad-smooth'),(99,4,15,13,'Winsor & Newton Sketching Paper Spiral Cartridge Pad 110gsm','Our medium-textured cartridge spiral pads are ideal for sketching and drawing with pencils, pastels and charcoals, holding line and graduation well. Winsor & Newton’s portable sketch pad opens perfectly flat and include easy to remove micro-perforated sheets.','winsor-newton-sketching-paper-spiral-pad'),(100,4,15,13,'Winsor & Newton Spiral Sketchbook 110gsm','These sketch books are made with 110gsm acid-free paper, to ensure longevity. Each sheet is perforated along the edge to allow for easy removal. They are suitable for use with pencil, pen and ink and light watercolour washes.These high quality black case bound hard black sketch books are available in two styles; one is case bound with a classic leather effect black cover and the second is a wire-o style hard backed sketch book. Both styles contain 80 perforated sheets of 110gsm cartridge paper.','winsor-newton-sprial-sketchbook'),(101,4,15,13,'Winsor & Newton Hardbound Sketchbook 110gsm','These sketch books are made with 110gsm acid-free paper, to ensure longevity. Each sheet is perforated along the edge to allow for easy removal. They are suitable for use with pencil, pen and ink and light watercolour washes.These high quality black case bound hard black sketch books are available in two styles; one is case bound with a classic leather effect black cover and the second is a wire-o style hard backed sketch book. Both styles contain 80 perforated sheets of 110gsm cartridge paper.','winsor-newton-hardbound-sketchbook'),(102,4,15,13,'Winsor & Newton Bristol Board 250gsm','The Bristol Board range is 250gsm/114lb in weight with an extra smooth, bright white surface. It is ideal for fine detail drawings and illustrations with pencil, technical pen, ink and airbrush. 100% acid and wood-free it has a strong surface for repeated working and erasing and is suitable for light washes without cockling.','winsor-newton-bristol-board'),(103,4,18,13,'Winsor & Newton Mixed Media Paper Spiral Pad 250gsm','Winsor & Newton’s mixed media paper is versatile and multipurpose. Heavyweight as well as non-absorbent, it combines the characteristics of watercolour and acrylic papers with those of drawing papers. Free from acids and optical brighteners, this paper is of archival quality for stability and resistance to ageing and is available in 250 gsm paper padof 30 sheets.','winsor-newton-mixed-media-paper-spiral-pad'),(104,4,18,13,'Winsor & Newton Black Mixed Media Paper Pad 200gsm','Winsor & Newton’s black mixed media paper is versatile and multipurpose for a variety of design&illustration, crafts and decorative arts. Ideal to use with white, opaque, and metallic colours, either in ink, marker, or across other wet and dry techniques to create contrasting and vibrant effects. Available in 200 gsm paper pads of 25 sheets.','winsor-newton-black-mixed-media-paper-pad'),(105,4,18,18,'Stillman & Birn Mixed Media Paper Nova Medium Grain 150gsm','Unbound sheets to work in plein aire, in a studio on an easel, or to be able to tape sheets to an art board for increased surface stability with wet techniques.','stillman-birn-mixed-media-paper-nova-medium'),(106,4,18,18,'Stillman & Birn Mixed Media Paper Beta Cold Press 150gsm','Unbound sheets to work in plein aire, in a studio on an easel, or to be able to tape sheets to an art board for increased surface stability with wet techniques.','stillman-birn-mixed-media-paper-beta-cold-press'),(107,4,18,18,'Stillman & Birn Mixed Media Paper Alpha Medium Grain 150gsm','Unbound sheets to work in plein aire, in a studio on an easel, or to be able to tape sheets to an art board for increased surface stability with wet techniques.','stillman-birn-mixed-media-paper-alpha-medium'),(108,4,18,18,'Stillman & Birn Mixed Media Paper Delta Cold Press 150gsm','Unbound sheets to work in plein aire, in a studio on an easel, or to be able to tape sheets to an art board for increased surface stability with wet techniques.','stillman-birn-mixed-media-paper-delta-cold-press'),(109,4,18,18,'Stillman & Birn Mixed Media Paper Epsilon Smooth Grain 150gsm','Unbound sheets to work in plein aire, in a studio on an easel, or to be able to tape sheets to an art board for increased surface stability with wet techniques.','stillman-birn-mixed-media-paper-epsilon-smooth'),(110,4,18,18,'Stillman & Birn Mixed Media Paper Gamma Medium Grain 150gsm','Unbound sheets to work in plein aire, in a studio on an easel, or to be able to tape sheets to an art board for increased surface stability with wet techniques.','stillman-birn-mixed-media-paper-gamma-medium'),(111,4,18,18,'Stillman & Birn Mixed Media Paper Zeta Smooth Grain 150gsm','Unbound sheets to work in plein aire, in a studio on an easel, or to be able to tape sheets to an art board for increased surface stability with wet techniques.','stillman-birn-mixed-media-paper-zeta-smooth'),(112,6,23,4,'Liquitex Bio Based Medium Matte Medium','A planet-positive way to give your paint a matte finish, while thinning and extending its volume. Or use as a collaging adhesive and fixative.','liquitex-bio-based-medium-matte-medium'),(113,6,23,4,'Liquitex Bio Based Medium Matte Gel','A planet-positive way to give your paint a matte finish, while thinning and extending its volume. Or use as a collaging adhesive and fixative.','liquitex-bio-based-medium-matte-gel'),(114,6,23,4,'Liquitex Bio Based Medium Gloss','A planet-positive way to give your paint a matte finish, while thinning and extending its volume. Or use as a collaging adhesive and fixative.','liquitex-bio-based-medium-gloss'),(115,6,23,4,'Liquitex Bio Based Medium Gloss Gel','A planet-positive way to give your paint a matte finish, while thinning and extending its volume. Or use as a collaging adhesive and fixative.','liquitex-bio-based-medium-gloss-gel'),(116,6,23,13,'Winsor & Newton Professional Acrylic Gloss Medium','Maintains no colour shift from wet to dry when used with Professional Acrylic. Increases the depth, transparency and flow of colour for blending or fine detail. Provides an even gloss finish. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-gloss-medium'),(117,6,23,13,'Winsor & Newton Professional Acrylic Gloss Medium','Gives colour a matte finish whilst also improving transparency and flow of the colour, great for blending or fine detail. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-matt-medium'),(118,6,24,13,'Winsor & Newton Professional Acrylic Gloss UV Varnish','Dries to an even gloss finish, and can be mixed with Professional Acrylic Matte Varnish to vary the final finish. Can be removed with Professional Acrylic Varnish Remover. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-gloss-uv-varnish'),(119,6,24,13,'Winsor & Newton Professional Acrylic Satin UV Varnish','Dries to an even satin finish. Can be removed with Professional Acrylic Varnish Remover. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-satin-uv-varnish'),(120,6,24,13,'Winsor & Newton Professional Acrylic Matt UV Varnish','Dries to an even matte finish, and can be mixed with Professional Acrylic Gloss Varnish to vary the final finish. Can be removed with Professional Acrylic Varnish Remover. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-matt-uv-varnish'),(121,6,24,4,'Liquitex Professional Mediums Gloss Varnish','Seal your acrylic work with a transparent, gloss acrylic layer which is breathable, permanent and protects against UV damage.','liqiutex-professional-mediums-gloss-varnish'),(122,6,24,4,'Liquitex Professional Mediums High Gloss Varnish','Seal your acrylic work with a transparent, high gloss acrylic layer which is breathable, permanent and protects against UV damage','liqiutex-professional-mediums-high-gloss-varnish'),(123,6,24,4,'Liquitex Professional Mediums Matte Varnish','Seal your acrylic work with a transparent, matte acrylic layer which is breathable, permanent and protects against UV damage.','liqiutex-professional-mediums-matte-varnish'),(124,6,24,4,'Liquitex Professional Mediums Soluver Matte Varnish Spray 400 ml','Seal your acrylic work with a transparent, matte acrylic layer which is breathable, permanent and protects against UV damage.','liquitex-professional-mediums-soluvar-matte-varnish-spray'),(125,6,24,4,'Liquitex Professional Mediums Matte Varnish Spray 400 ml','Seal your acrylic work with a transparent, matte acrylic layer which is breathable, permanent and protects against UV damage','liquitex-professional-mediums-matte-varnish-spray'),(126,6,24,4,'Liquitex Professional Mediums Gloss Varnish Spray 400 ml','Seal your acrylic work with a transparent, gloss acrylic layer which is breathable, permanent and protects against UV damage.','liquitex-professional-mediums-gloss-varnish-spray'),(127,6,25,4,'Liquitex Professional Mediums Modeling Paste','Acrylic and marble putty to build texture on rigid supports and create 3D forms.','liquitex-professional-mediums-modeling-paste'),(128,6,25,4,'Liquitex Professional Mediums Flexible Modeling Paste','Acrylic and marble putty to build textures on semi-flexible supports and create 3D forms.','liquitex-professional-mediums-flexible-modeling-paste'),(129,6,25,4,'Liquitex Professional Mediums Gloss Gel Medium','Increase gloss, extend volume and thicken, while extending open time - or use as a collaging adhesive.','liquitex-professional-mediums-gloss-gel-medium'),(130,6,25,4,'Liquitex Professional Mediums Matte Gel','Reduce shine, extend volume and thicken, while extending open time - or use as a strong collaging adhesive.','liquitex-professional-mediums-matte-gel'),(131,6,25,13,'Winsor & Newton Professional Acrylic Mediums Modeling Paste','This modelling paste is lightweight and flexible so it doesn’t shrink or crack. Increases opacity, body and structure and is ideal for carving, sanding and building extreme textures. It can be used to build up depth in layers, and either overpainted when dry or mixed with colour. Dries to an even matte finish. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-mediums-modeling-paste'),(132,6,25,13,'Winsor & Newton Professional Acrylic Mediums Gloss Gel','Maintains no colour shift from wet to dry when used with Professional Acrylic. Increases transparency, depth and gloss of colour and maintains the thickness of the colour with good brush stroke retention. Dries to an even gloss finish. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-mediums-gloss-gel'),(133,6,25,13,'Winsor & Newton Professional Acrylic Mediums Matt Gel','Gives colour a matte finish whilst also maintaining the thickness of the colour with good brush stroke retention. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-mediums-matt-gel'),(134,6,26,4,'Liquitex Professional Mediums Flow-aid Additive 118 ml','Dramatically increase the flow of your color/mediums while minimizing brush strokes.','liquitex-professional-mediums-flow-aid-additive'),(135,6,26,4,'Liquitex Professional Mediums Liquithick Additive 237 ml','Create custom viscosity and a matte finish without increasing paint transparency.','liquitex-professional-mediums-liquithick-additive'),(136,6,26,4,'Liquitex Professional Mediums Slow-Dri Fluid Additive 118 ml','Slow drying time by 40%, without affecting color opacity, so you can work your paint for longer.','liquitex-professional-mediums-slow-dri-fluid-additive'),(137,6,26,4,'Liquitex Professional Mediums Slow-Dri Gel Additive 237 ml','Slow drying time by 40%, without affecting color opacity, so you can work it for longer.','liquitex-professional-mediums-slow-dri-gel-additive'),(138,6,26,13,'Winsor & Newton Professional Acrylic Mediums Flow Improver','Maintains no colour shift from wet to dry when used with Professional Acrylic. Increases the flow of colour allowing the application of areas of flat, even colour without changing colour strength. Also maintains the stability of colour and slightly slows drying. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-mediums-flow-improver'),(139,6,26,13,'Winsor & Newton Professional Acrylic Slow Drying Medium','Maintains no colour shift from wet to dry when used with Professional Acrylic. Slows drying to give more working time of colour for extended blending and manipulation. Please note this product is going through a transition period with the label, you may receive products labelled as ARTISTS\' instead of PROFESSIONAL, rest assured the formula remains the same.','winsor-newton-professional-acrylic-slow-drying-medium'),(140,5,21,4,'Liquitex Muted Collection Ink Set','Discover Acrylic Ink, our ultra-fluid professional acrylic. Originally a special release, now permanent, this set brings together the full range of Acrylic Ink muted colors and Titanium White to create tints and pastels.','liquitex-muted-collection-ink-set'),(141,1,2,4,'Liquitex Heavy Body Acrylic Set 6x22ml Classic','Heavy Body Acrylic is our highest viscosity professional acrylic. Broaden your palette with this collection of classic and popular colors.','liquitex-heavy-body-acrylic-set-6x22ml-classic'),(142,1,1,13,'Winsor & Newton Winton Oil Colors','Winton Oil Colour offers quality and affordability by using moderately priced pigments, rather than reducing the pigment load and compromising colour performance. The high level of pigmentation provides good covering power and tinting strength.','winsor-newton-winton-oil-colors'),(143,4,15,18,'Stillman & Birn Alpha Series Softcover Premium Sketchbook','The Alpha Series Sketchbook from Stillman & Birn features heavyweight, 150 gsm (100 lb cover) white paper that has been carefully sewn into a flexible and rugged softcover binding. The white, mixed media paper has a medium grain surface and works well with all dry media, light washes, and inks. Special rounded corners prevent frayed edges. This portrait sketchbook comes in a few different sizes.  42 sheets, 92 pages.','stillman-birn-alpha-softcover'),(144,4,15,18,'Stillman & Birn Beta Series Softcover Premium Sketchbook','The Beta Series Sketchbook from Stillman & Birn features extra heavyweight, 270 gsm (100 lb cover) white paper that has been carefully sewn into a flexible and rugged softcover binding. The mixed media, cold press paper boasts a substantial tooth with enhanced wet and tear strength. Perfect for dry and wet media, watercolor and ink. Special rounded corners prevent frayed edges. 28 sheets, 56 pages, 5.5\" x 8.5\".','stillman-birn-beta-softcover'),(145,4,15,18,'Stillman & Birn Gamma Series Softcover Premium Sketchbook','The Gamma Series Sketchbook from Stillman & Birn features heavyweight, 150 gsm (100 lb cover) ivory paper that has been carefully sewn into a flexible and rugged softcover binding. The mixed media, medium grain paper works well with dry media, light washes and inks. Special rounded corners prevent frayed edges.  48 sheets, 96 pages, 5.5\" x 8.5\".','stillman-birn-gamma-softcover'),(146,4,15,18,'Stillman & Birn Nova Series Softcover Premium Sketchbook','The Nova Series Sketchbook from Stillman & Birn features heavyweight, 150 gsm white paper that has been carefully sewn into a flexible and rugged softcover binding. The white, mixed media paper has a medium grain surface and works well with all dry media, light washes, and inks. Special rounded corners prevent frayed edges. 46 sheets, 92 pages, 5.5\" x 8.5\".','stillman-birn-nova-softcover'),(147,4,15,18,'Stillman & Birn Epsilon Series Softcover Premium Sketchbook','The Epsilon Series Sketchbook from Stillman & Birn features heavyweight, 150 gsm (100 lb cover) white paper that has been carefully sewn into a flexible and rugged softcover binding. The mixed media, smooth paper is great for pen & ink, dry media and light washes. Special rounded corners prevent frayed edges. 48 sheets, 96 pages.','stillman-birn-epsilon-softcover'),(148,1,4,4,'Liquitex Professional Acrylic Gouache','Meet Acrylic Gouache, the most highly pigmented of all our paints. This color set gives you endless mixing possibilities, while Titanium White and Mars Black can be used on their own or to tint and shade.','liquitex-acrylic-gouache'),(149,1,3,13,'Winsor & Newton Cotman Watercolor Set  - Pocket Set','Discover Cotman Watercolours made with quality, fine art pigments in a pocket-sized set. Includes a brush and palettes with multiple mixing areas. Palette Pocket Set was previously named Pocket Plus.','winsor-newton-cotman-watercolor-pocket-set');
