DROP TABLE IF EXISTS `product_item`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `product_item` (
  `product_item_id` int NOT NULL,
  `product_group_id` int NOT NULL,
  `color_id` int DEFAULT NULL,
  `size_id` int DEFAULT NULL,
  `price` decimal(10,2) NOT NULL,
  PRIMARY KEY (`product_item_id`),
  KEY `ProductGroupID` (`product_group_id`),
  KEY `ColorID` (`color_id`),
  KEY `SizeID` (`size_id`),
  CONSTRAINT `product_item_ibfk_1` FOREIGN KEY (`product_group_id`) REFERENCES `product_group` (`product_group_id`),
  CONSTRAINT `product_item_ibfk_2` FOREIGN KEY (`color_id`) REFERENCES `product_color` (`color_id`),
  CONSTRAINT `product_item_ibfk_3` FOREIGN KEY (`size_id`) REFERENCES `product_size` (`size_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

